1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
4	type Step = { op: "quote"; items: Item[] };
5	type Scenario = { customer: unknown; steps: Step[] };
6	type QuoteResult = { premium: number };
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
17	
18	const basePremium = (items: Item[]): number =>
19	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
20	
21	const quote = (items: Item[]): QuoteResult => {
22	  // first-insurance surcharge 10%: base * 11 / 10
23	  const premium = Math.ceil((basePremium(items) * 11) / 10 + PROCESSING_FEE);
24	  return { premium };
25	};
26	
27	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
28	  const results = scenario.steps.map((step) => quote(step.items));
29	  return { results };
30	};
